CREATE TABLE IF NOT EXISTS public.aset_bast (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), nomor text NOT NULL, pemberi_user uuid, penerima_user uuid, opd_id uuid, tanggal date DEFAULT CURRENT_DATE NOT NULL, catatan text, status text DEFAULT 'issued' NOT NULL, created_by uuid, approved_by uuid, approved_at timestamptz, created_at timestamptz DEFAULT now() NOT NULL, updated_at timestamptz DEFAULT now() NOT NULL);
