DO $$ DECLARE r record; BEGIN
  FOR r IN SELECT tablename FROM pg_tables WHERE schemaname='public' LOOP
    EXECUTE format('GRANT SELECT, INSERT, UPDATE, DELETE ON public.%I TO authenticated', r.tablename);
    EXECUTE format('GRANT ALL ON public.%I TO service_role', r.tablename);
    EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', r.tablename);
  END LOOP;
END $$;

DO $$ DECLARE r record; BEGIN
  FOR r IN SELECT tablename FROM pg_tables WHERE schemaname='public' AND tablename IN (
    'aset_bast','aset_bast_items','aset_mutasi','aset_opname','aset_opname_items','aset_pemeliharaan','aset_penyusutan_history','aset_verification_campaign','aset_verification_item',
    'attendance_shift_assignment','attendance_shifts','compliance_checklist','consent_log','cron_history','dataset_submission','dataset_submission_review','dataset_template',
